// apiService.js

const BASE_URL = 'https://api.example.com';

// Token storage (in-memory; in production, use SecureStore or AsyncStorage)
let authToken = null;
let refreshToken = null;

// ============================================
// Helper: Get stored tokens
// ============================================
const getAuthToken = () => authToken;
const getRefreshToken = () => refreshToken;

const setTokens = (access, refresh) => {
  authToken = access;
  refreshToken = refresh;
};

const clearTokens = () => {
  authToken = null;
  refreshToken = null;
};

// ============================================
// Helper: Build headers
// ============================================
const buildHeaders = (authenticated = true, customHeaders = {}) => {
  const headers = {
    'Content-Type': 'application/json',
    'Accept': 'application/json',
    ...customHeaders,
  };

  if (authenticated && authToken) {
    headers['Authorization'] = `Bearer ${authToken}`;
  }

  return headers;
};

// ============================================
// Helper: Handle API response
// ============================================
const handleResponse = async (response) => {
  const contentType = response.headers.get('content-type');
  let data;

  if (contentType && contentType.includes('application/json')) {
    data = await response.json();
  } else {
    data = await response.text();
  }

  if (!response.ok) {
    const error = {
      status: response.status,
      statusText: response.statusText,
      data,
    };

    // If unauthorized, try token refresh
    if (response.status === 401) {
      throw { ...error, isAuthError: true };
    }

    throw error;
  }

  return data;
};

// ============================================
// Core: API request with retry & token refresh
// ============================================
const apiRequest = async (endpoint, options = {}, retryCount = 0) => {
  const {
    method = 'GET',
    body = null,
    authenticated = true,
    headers: customHeaders = {},
    timeout = 30000,
    queryParams = {},
  } = options;

  // Build URL with query params
  let url = `${BASE_URL}${endpoint}`;
  const queryString = Object.entries(queryParams)
    .filter(([, value]) => value !== undefined && value !== null)
    .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(value)}`)
    .join('&');

  if (queryString) {
    url += `?${queryString}`;
  }

  // Build fetch config
  const fetchConfig = {
    method,
    headers: buildHeaders(authenticated, customHeaders),
  };

  if (body && method !== 'GET') {
    fetchConfig.body = JSON.stringify(body);
  }

  // Implement timeout using AbortController
  const controller = new AbortController();
  fetchConfig.signal = controller.signal;
  const timeoutId = setTimeout(() => controller.abort(), timeout);

  try {
    const response = await fetch(url, fetchConfig);
    clearTimeout(timeoutId);
    return await handleResponse(response);
  } catch (error) {
    clearTimeout(timeoutId);

    // Handle abort/timeout
    if (error.name === 'AbortError') {
      throw {
        status: 0,
        statusText: 'Request Timeout',
        data: { message: `Request to ${endpoint} timed out after ${timeout}ms` },
      };
    }

    // Handle network errors
    if (error instanceof TypeError && error.message === 'Network request failed') {
      throw {
        status: 0,
        statusText: 'Network Error',
        data: { message: 'No internet connection or server is unreachable' },
      };
    }

    // Handle 401 with token refresh (retry once)
    if (error.isAuthError && retryCount === 0 && refreshToken) {
      try {
        await tokenRefresh();
        return await apiRequest(endpoint, options, retryCount + 1);
      } catch (refreshError) {
        clearTokens();
        throw {
          status: 401,
          statusText: 'Session Expired',
          data: { message: 'Your session has expired. Please log in again.' },
        };
      }
    }

    throw error;
  }
};

