// ExampleScreen.js
import React, { useEffect } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  ActivityIndicator,
  Alert,
  StyleSheet,
  ScrollView,
} from 'react-native';
import ApiService from './apiService';
import useApi from './useApi';

const ExampleScreen = () => {
  // Hook instances for different API calls
  const loginApi = useApi(ApiService.login);
  const profileApi = useApi(ApiService.getProfile);
  const updateProfileApi = useApi(ApiService.updateProfile);
  const itemsApi = useApi((page) =>
    ApiService.getPaginatedData('items', page, 10)
  );

  // Login handler
  const handleLogin = async () => {
    try {
      const result = await loginApi.execute('user@example.com', 'password123');
      Alert.alert('Success', `Welcome, ${result.user.firstName}!`);
      // Fetch profile after login
      await profileApi.execute();
    } catch (err) {
      Alert.alert('Login Failed', err.data?.message || 'Unknown error');
    }
  };

  // Update profile handler
  const handleUpdateProfile = async () => {
    try {
      await updateProfileApi.execute({
        firstName: 'John',
        lastName: 'Doe',
        bio: 'Updated bio from the app',
      });
      Alert.alert('Success', 'Profile updated!');
      // Refresh profile data
      await profileApi.execute();
    } catch (err) {
      Alert.alert('Update Failed', err.data?.message || 'Unknown error');
    }
  };

  // Load items
  const handleLoadItems = async () => {
    try {
      await itemsApi.execute(1);
    } catch (err) {
      Alert.alert('Error', err.data?.message || 'Failed to load items');
    }
  };

  // Logout handler
  const handleLogout = async () => {
    await ApiService.logout();
    profileApi.reset();
    itemsApi.reset();
    Alert.alert('Logged Out', 'You have been logged out.');
  };

  return (
    <ScrollView style={styles.container}>
      <Text style={styles.title}>API Service Demo</Text>

      {/* Login Section */}
      <View style={styles.section}>
        <Text style={styles.sectionTitle}>Authentication</Text>
        <TouchableOpacity
          style={styles.button}
          onPress={handleLogin}
          disabled={loginApi.loading}
        >
          {loginApi.loading ? (
            <ActivityIndicator color="#fff" />
          ) : (
            <Text style={styles.buttonText}>Login</Text>
          )}
        </TouchableOpacity>
        <TouchableOpacity
          style={[styles.button, styles.logoutButton]}
          onPress={handleLogout}
        >
          <Text style={styles.buttonText}>Logout</Text>
        </TouchableOpacity>
      </View>

      {/* Profile Section */}
      <View style={styles.section}>
        <Text style={styles.sectionTitle}>Profile</Text>
        {profileApi.loading && <ActivityIndicator />}
        {profileApi.error && (
          <Text style={styles.errorText}>
            Error: {profileApi.error.data?.message || 'Failed to load profile'}
          </Text>
        )}
        {profileApi.data && (
          <View style={styles.profileCard}>
            <Text style={styles.profileName}>
              {profileApi.data.firstName} {profileApi.data.lastName}
            </Text>
            <Text style={styles.profileEmail}>{profileApi.data.email}</Text>
            {profileApi.data.bio && (
              <Text style={styles.profileBio}>{profileApi.data.bio}</Text>
            )}
          </View>
        )}
        <TouchableOpacity
          style={styles.button}
          onPress={handleUpdateProfile}
          disabled={updateProfileApi.loading}
        >
          {updateProfileApi.loading ? (
            <ActivityIndicator color="#fff" />
          ) : (
            <Text style={styles.buttonText}>Update Profile</Text>
          )}
        </TouchableOpacity>
      </View>

      {/* Data Section */}
      <View style={styles.section}>
        <Text style={styles.sectionTitle}>Items</Text>
        <TouchableOpacity
          style={styles.button}
          onPress={handleLoadItems}
          disabled={itemsApi.loading}
        >
          {itemsApi.loading ? (
            <ActivityIndicator color="#fff" />
          ) : (
            <Text style={styles.buttonText}>Load Items</Text>
          )}
        </TouchableOpacity>
        {itemsApi.data?.items?.map((item, index) => (
          <View key={item.id || index} style={styles.itemCard}>
            <Text style={styles.itemTitle}>{item.title}</Text>
            <Text style={styles.itemDescription}>{item.description}</Text>
          </View>
        ))}
      </View>
    </ScrollView>
  );
};

